#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    vector<vector<int>> adj(n + 1);
    for (int i = 0; i < n - 1; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    vector<int> depth(n + 1, -1);
    queue<int> q;
    q.push(1);
    depth[1] = 0;
    while (!q.empty()) {
        int cur = q.front(); q.pop();
        for (int nxt : adj[cur]) {
            if (depth[nxt] == -1) {
                depth[nxt] = depth[cur] + 1;
                q.push(nxt);
            }
        }
    }
    for (int i = 1; i <= n; i++) cout << depth[i] << "\n";
    return 0;
}
